<html><head><meta charset="utf-8"><title>Streaming agent</title>
<style>body{font-family:system-ui,sans-serif;max-width:780px;margin:30px auto;padding:0 16px;background:#fafafa}#log{background:#1e1e1e;color:#e0e0e0;padding:16px;border-radius:8px;min-height:240px;white-space:pre-wrap;font:14px ui-monospace,monospace}.ev-token{color:#7ec699}.ev-tool{color:#f9c74f}.ev-error{color:#ff6b6b}.ev-final{color:#4cc9f0;font-weight:bold}#in{width:calc(100% - 90px);padding:8px}button{padding:8px 16px}</style>
</head><body>
<h2>Streaming agent (SSE)</h2>
<input id="in" placeholder="Спроси что-нибудь…" autofocus>
<button id="go">▶</button>
<pre id="log"></pre>
<script>
const log = document.getElementById('log');
const input = document.getElementById('in');
const go = document.getElementById('go');

function append(html) {
    log.innerHTML += html + '\n';
    log.scrollTop = log.scrollHeight;
}

async function ask(q) {
    log.innerHTML = '';
    append('<span style="color:#888">→ ' + q + '</span>');
    let res;
    try {
        res = await fetch('/stream/agent', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ input: q, stream: true }),
        });
    } catch (e) { append('<span class="ev-error">network error: ' + e.message + '</span>'); return; }
    if (!res.ok || !res.body) { append('<span class="ev-error">http ' + res.status + '</span>'); return; }

    const reader = res.body.getReader();
    const dec = new TextDecoder();
    let buf = '', out = '';
    while (true) {
        const { value, done } = await reader.read();
        if (done) break;
        buf += dec.decode(value, { stream: true });
        let idx;
        while ((idx = buf.indexOf('\n\n')) >= 0) {
            const frame = buf.slice(0, idx); buf = buf.slice(idx + 2);
            let ev = 'message', data = '';
            for (const line of frame.split('\n')) {
                if (line.startsWith('event:')) ev = line.slice(6).trim();
                else if (line.startsWith('data:')) data += line.slice(5).trim();
            }
            let obj = {};
            try { obj = JSON.parse(data); } catch (_) {}
            if (ev === 'token') {
                out += obj.delta || '';
                const lines = log.innerHTML.split('\n');
                if (lines.length && lines[lines.length-1].startsWith('<span class="ev-token">')) {
                    lines[lines.length-1] = '<span class="ev-token">' + out + '</span>';
                    log.innerHTML = lines.join('\n');
                } else {
                    append('<span class="ev-token">' + out + '</span>');
                }
                log.scrollTop = log.scrollHeight;
            } else if (ev === 'tool_call') {
                append('<span class="ev-tool">[tool] ' + (obj.tool || '?') + '(' + JSON.stringify(obj.input) + ')</span>');
            } else if (ev === 'tool_result') {
                append('<span class="ev-tool">[result] ' + String(obj.output || '').slice(0,200) + '</span>');
            } else if (ev === 'final') {
                append('<span class="ev-final">✓ done in ' + obj.durationMs + 'ms, ' + (obj.steps||[]).length + ' steps</span>');
            } else if (ev === 'error') {
                append('<span class="ev-error">✗ ' + (obj.message || 'error') + '</span>');
            }
        }
    }
}
go.onclick = () => { if (input.value.trim()) ask(input.value.trim()); };
input.addEventListener('keydown', e => { if (e.key === 'Enter' && input.value.trim()) ask(input.value.trim()); });
</script></body></html>`;
